// src/services/authService.js
import api from './api';

class AuthService {
    async register(userData) {
        try {
            const response = await api.post('/auth/register', {
                username: userData.username,
                email: userData.email,
                password: userData.password,
                healthRecordId: userData.healthRecordId
            });
            return response.data;
        } catch (error) {
            throw this.handleError(error);
        }
    }

    async loginWithFingerprint(username, fingerprintId = null) {
        try {
            // Send both username and fingerprintId to the backend
            const response = await api.post('/auth/login/fingerprint', { 
                username,
                fingerprintId  // Include the fingerprint ID from the scan
            });
            
            if (response.data.token) {
                localStorage.setItem('authToken', response.data.token);
                localStorage.setItem('user', JSON.stringify(response.data.user));
            }
            return response.data;
        } catch (error) {
            throw this.handleError(error);
        }
    }

    async loginWithPassword(username, password) {
        try {
            const response = await api.post('/auth/login/password', { username, password });
            if (response.data.token) {
                localStorage.setItem('authToken', response.data.token);
                localStorage.setItem('user', JSON.stringify(response.data.user));
            }
            return response.data;
        } catch (error) {
            throw this.handleError(error);
        }
    }

    async getProfile() {
        try {
            const response = await api.get('/auth/profile');
            return response.data;
        } catch (error) {
            throw this.handleError(error);
        }
    }

    async updateProfile(profileData) {
        try {
            const response = await api.put('/auth/profile', profileData);
            if (response.data.user) {
                const currentUser = JSON.parse(localStorage.getItem('user') || '{}');
                const updatedUser = { ...currentUser, ...response.data.user };
                localStorage.setItem('user', JSON.stringify(updatedUser));
            }
            return response.data;
        } catch (error) {
            throw this.handleError(error);
        }
    }

    async changePassword(currentPassword, newPassword) {
        try {
            const response = await api.post('/auth/change-password', {
                currentPassword,
                newPassword
            });
            return response.data;
        } catch (error) {
            throw this.handleError(error);
        }
    }

    async enrollFingerprint() {
        try {
            const response = await api.post('/auth/enroll-fingerprint');
            return response.data;
        } catch (error) {
            throw this.handleError(error);
        }
    }

    async verifyToken() {
        try {
            const response = await api.get('/auth/verify');
            return response.data;
        } catch (error) {
            throw this.handleError(error);
        }
    }

    logout() {
        localStorage.removeItem('authToken');
        localStorage.removeItem('user');
    }

    getCurrentUser() {
        const userStr = localStorage.getItem('user');
        return userStr ? JSON.parse(userStr) : null;
    }

    getToken() {
        return localStorage.getItem('authToken');
    }

    handleError(error) {
        if (error.response) {
            return new Error(error.response.data.error || 'Server error');
        } else if (error.request) {
            return new Error('No response from server');
        } else {
            return new Error('Request failed');
        }
    }
}

const authService = new AuthService();
export default authService;
